const createVM = (name, node, vnode) => {
  try {
    // Try to parse the vue template
    const vt = parseVueTemplate(node.textContent)
    if (!vt) {
      return null
    }

    const { template, options } = vt

    // Create a placeholder after node container
    const container = node.parentNode
    const holder = document.createElement('div')
    container.parentNode.insertBefore(holder, container)

    // Create VM
    return new Vue({
      ...options,
      el: holder,
      template: `<div class="bd-example vue-example vue-example-${name}" translate="no">${template}</div>`,
      router: vnode.context.$router
    })
  } catch (e) {
    console.error('[v-play]', e)
  }

  return null
}

const processComponentGroup = groupSlug => {
  // Array of components in the group
  const groupMeta = componentGroups[groupSlug] || {}
  const componentsMeta = groupMeta.components || []
  const directivesMeta = groupMeta.directives || []

  // The URL to the components docs
  const docUrl = `${baseDocs}/docs/components/${groupSlug}/`.replace('//', '/')

  // We import the component from the transpiled `esm/` dir
  const groupRef = require(path.resolve(baseDir, 'esm/components/' + (groupSlug || '')))

  // Process each component
  componentsMeta.forEach(meta => {
    processComponentMeta(meta, groupRef, groupMeta.description, docUrl)
  })

  // Process any directives provided in the meta
  // These directives do not have their own `package.json` files
  directivesMeta.forEach(directiveMeta => {
    processDirectiveMeta(directiveMeta, groupMeta.description, docUrl)
  })
}

export const paginationMixin = extend({
  props,
  computed: {
    localPaging() {
      return this.hasProvider ? !!this.noProviderPaging : true
    },
    paginatedItems() {
      const { sortedItems, filteredItems, localItems } = safeVueInstance(this)
      let items = sortedItems || filteredItems || localItems || []
      const currentPage = mathMax(toInteger(this.currentPage, 1), 1)
      const perPage = mathMax(toInteger(this.perPage, 0), 0)
      // Apply local pagination
      if (this.localPaging && perPage) {
        // Grab the current page of data (which may be past filtered items limit)
        items = items.slice((currentPage - 1) * perPage, currentPage * perPage)
      }
      // Return the items to display in the table
      return items
    }
  }
})

export const hasListenerMixin = extend({
  methods: {
    hasListener(name) {
      if (isVue3) {
        return true
      }
      // Only includes listeners registered via `v-on:name`
      const $listeners = this.$listeners || {}
      // Includes `v-on:name` and `this.$on('name')` registered listeners
      // Note this property is not part of the public Vue API, but it is
      // the only way to determine if a listener was added via `vm.$on`
      const $events = this._events || {}
      // Registered listeners in `this._events` are always an array,
      // but might be zero length
      return !isUndefined($listeners[name]) || (isArray($events[name]) && $events[name].length > 0)
    }
  }
})

export const BNav = /*#__PURE__*/ extend({
  name: NAME_NAV,
  functional: true,
  props,
  render(h, { props, data, children }) {
    const { tabs, pills, vertical, align, cardHeader } = props

    return h(
      props.tag,
      mergeData(data, {
        staticClass: 'nav',
        class: {
          'nav-tabs': tabs,
          'nav-pills': pills && !tabs,
          'card-header-tabs': !vertical && cardHeader && tabs,
          'card-header-pills': !vertical && cardHeader && pills && !tabs,
          'flex-column': vertical,
          'nav-fill': !vertical && props.fill,
          'nav-justified': !vertical && props.justified,
          [computeJustifyContent(align)]: !vertical && align,
          small: props.small
        }
      }),
      children
    )
  }
})

export const BSkeletonTable = /*#__PURE__*/ extend({
  name: NAME_SKELETON_TABLE,
  functional: true,
  props,
  render(h, { data, props }) {
    const { animation, columns } = props

    const $th = h('th', [h(BSkeleton, { props: { animation } })])
    const $thTr = h('tr', createArray(columns, $th))

    const $td = h('td', [h(BSkeleton, { props: { width: '75%', animation } })])
    const $tdTr = h('tr', createArray(columns, $td))
    const $tbody = h('tbody', createArray(props.rows, $tdTr))

    const $thead = !props.hideHeader ? h('thead', [$thTr]) : h()
    const $tfoot = props.showFooter ? h('tfoot', [$thTr]) : h()

    return h(BTableSimple, mergeData(data, { props: { ...props.tableProps } }), [
      $thead,
      $tbody,
      $tfoot
    ])
  }
})

const normalizedOptions = computed(() =>
  (props.options ?? []).map(
    (el) =>
      (typeof el === 'string' || typeof el === 'number' || typeof el === 'boolean'
        ? {
            value: el,
            disabled: props.disabled,
            text: el.toString(),
          }
        : {
            value: (el as Record<string, unknown>)[props.valueField as string],
            disabled:
              props.disabled ||
              (((el as Record<string, unknown>)[props.disabledField as string] as
                | boolean
                | undefined) ??
                false),
            text:
              ((el as Record<string, unknown>)[props.textField as string] as string | undefined) ??
              String((el as Record<string, unknown>)[props.valueField as string]),
          }) as {text: string; value: CheckboxValue; disabled: boolean}
  )
)

const normalizedOptions = computed<Array<{text: string; value: CheckboxValue; disabled: boolean}>>(
  () =>
    props.options.map((option) => {
      if (typeof option === 'object' && option !== null) {
        // Ensure text and disabled are defined, with group disabled taking precedence
        return {
          ...option,
          text: option.text ?? String(option.value ?? ''),
          value: option.value ?? null,
          disabled: props.disabled ? true : (option.disabled ?? false),
        }
      }
      // Primitive value - normalize to {text, value}, with group disabled taking precedence
      return {
        text: String(option),
        value: option,
        disabled: props.disabled,
      }
    })
)

const processedAttrs = computed(() => {
  // In plain mode, pass all attributes to the input element
  if (props.plain) {
    return {
      rootAttrs: {},
      dropZoneAttrs: {},
      inputAttrs: attrs,
    }
  }
  // In custom mode, split attributes:
  // - class/style go to root (for layout/positioning)
  // - title goes to drop zone (for tooltip on interactive element)
  // - everything else goes to hidden input (for form functionality)
  const {class: rootClass, style: rootStyle, title: dropZoneTitle, ...inputAttrs} = attrs
  const rootAttrs: Record<string, unknown> = {}
  const dropZoneAttrs: Record<string, unknown> = {}
  if (rootClass !== undefined) rootAttrs.class = rootClass
  if (rootStyle !== undefined) rootAttrs.style = rootStyle
  if (dropZoneTitle !== undefined) dropZoneAttrs.title = dropZoneTitle
  return {
    rootAttrs,
    dropZoneAttrs,
    inputAttrs,
  }
})

const isElementAndTriggerOutside = () => {
  const triggerRect = triggerElement.value?.getBoundingClientRect()
  const elementRect = floatingElement.value?.getBoundingClientRect()
  const margin = Number.parseInt(props.hideMargin as unknown as string, 10) || 0
  const offsetX = getSafeWindow()?.scrollX || 0
  const offsetY = getSafeWindow()?.scrollY || 0
  const triggerIsOutside =
    !triggerRect ||
    x.value < triggerRect.left + offsetX - margin ||
    x.value > triggerRect.right + offsetX + margin ||
    y.value < triggerRect.top + offsetY - margin ||
    y.value > triggerRect.bottom + offsetY + margin

  const isOutside =
    !elementRect ||
    x.value < elementRect.left + offsetX - margin ||
    x.value > elementRect.right + offsetX + margin ||
    y.value < elementRect.top + offsetY - margin ||
    y.value > elementRect.bottom + offsetY + margin

  return {triggerIsOutside, isOutside}
}

const updateTabElementsArray = () => {
  const tabElements = flattenFragments(slots.default?.({}) ?? [])
  tabElementsArray.value = (Array.isArray(tabElements) ? tabElements : [tabElements]).filter(
    (tab) => tab.type === BTab
  )
  // only get the ids once in setup context
  if (initialIds.value.length === 0) {
    // we need to get the ids of the tabs before they are registered. After that we use the internalId for the tabpane
    initialIds.value = tabElementsArray.value.map((tab) =>
      unref(useId(() => tab.props?.id, 'tabpane'))
    )
    // Check if any tab has an explicit ID
    hasExplicitIds.value = tabElementsArray.value.some((tab) => tab.props?.id !== undefined)
  }
  isChildActive.value = tabElementsArray.value.some(
    (tab) => tab.props?.active !== undefined && tab.props?.active !== false
  )
}

const handleUnmount = (
  el: Element,
  binding: DirectiveBinding<string | readonly string[] | undefined>,
  vnode: VNode
) => {
  // Determine targets
  const targets = getTargets(binding, el)
  if (targets.length === 0) return
  const provides = findProvides(binding, vnode, true)
  const showHideMap =
    (provides as Record<symbol, RegisterShowHideValue>)[showHideRegistryKey]?.values ?? null

  targets.forEach((targetId) => {
    const showHide = getActiveShowHide(showHideMap, targetId)
    if (!showHide) {
      return
    }
    // Pass clean=true to let the composable handle cleanup of aria-expanded and classes
    showHide.unregisterTrigger('click', el, true)
  })

  // Only remove what the directive manages (aria-controls)
  // aria-expanded and classes are managed by useShowHide composable
  el.removeAttribute('aria-controls')
  delete (el as HTMLElement).dataset.bvtoggle
}

const sortAccordionItems = () => {
  accordionItems.value = [...accordionItems.value].sort((a, b) =>
    sortSlotElementsByPosition(unref(a.el), unref(b.el))
  )
  if (modelValue.value) {
    if (isReadOnlyArray(modelValue.value)) {
      const next = modelValue.value
        .map((id) => accordionItems.value.findIndex((item) => item.id === id))
        .filter((i) => i !== -1)

      if (next.length !== modelValue.value.length) {
        if (process.env.NODE_ENV === 'development') {
          console.warn('[BAccordion] Unknown item id in v-model:', modelValue.value)
        }
      }
      index.value = next
    } else {
      const idx = accordionItems.value.findIndex((item) => item.id === modelValue.value)
      if (idx !== -1) index.value = idx
    }
  } else if (index.value !== undefined) {
    modelValue.value = isReadOnlyArray(index.value)
      ? index.value.map((idx) => accordionItems.value[idx]?.id).filter((el) => el !== undefined)
      : accordionItems.value[index.value]?.id
  }
}

